from dataclasses import dataclass
from decimal import Decimal

@dataclass
class Transaction:
    tx_id: str
    amount: Decimal
    currency: str

    def __post_init__(self):
        if not isinstance(self.amount, Decimal):
            raise ValueError('amount must be Decimal')
        if self.amount <= 0:
            raise ValueError('amount must be > 0')
        if self.currency != 'PEN':
            raise ValueError('currency PEN only')

print(Transaction('T1', Decimal('10.00'), 'PEN'))
for bad in [(Decimal('0'), 'PEN'), (Decimal('10'), 'EUR'), (10.0, 'PEN')]:
    try:
        Transaction('T', bad[0], bad[1])
    except ValueError as e:
        print('reject', e)

from dataclasses import dataclass

@dataclass
class ClientRecord:
    client_id: str
    region: str

    @classmethod
    def from_dict(cls, d):
        if not d.get('client_id') or not d.get('region'):
            raise ValueError('missing fields')
        return cls(d['client_id'], d['region'])

print(ClientRecord.from_dict({'client_id': 'C1', 'region': 'Lima'}))

