from typing import Protocol

class EntityStore(Protocol):
    def get(self, entity_id: str): ...
    def save(self, entity) -> None: ...

class MemoryStore:
    def __init__(self):
        self._d = {}
    def get(self, entity_id: str):
        return self._d.get(entity_id)
    def save(self, entity) -> None:
        self._d[entity['id']] = entity

s = MemoryStore()
s.save({'id': 'C1'})
print(s.get('C1'))

class FakeStore:
